/*
** The technique for requiring arguments on table-valued functions
** described at:
**
**   https://sqlite.org/vtab.html#erpotvf
**
** does not work.  To see the problem, save the code shown here into
** a file named "testvtab.c" and then compile it (on Linux) as follows:
**
**  gcc -Wall -g -shared -fPIC -I. -DSQLITE_DEBUG ./testvtab.c -o ./testvtab.so
**
** Then run the following script in the CLI:
**
**    .load ./testvtab.so
**    SELECT * FROM testvtab(0) WHERE x=1 OR x=2;
*/
#include <sqlite3ext.h>
SQLITE_EXTENSION_INIT1
#include <stdlib.h>
#include <stdio.h>

int xConnect(sqlite3 *xdb, void *aux, int na1, const char *const *na2,
             sqlite3_vtab **tab, char **na3) {
  const char *sql = "CREATE TABLE x(x INT, p1 INT HIDDEN)";
# define X_COLUMN 0
# define P1_COLUMN 1
  sqlite3_declare_vtab(xdb, sql);
  *tab = malloc(sizeof(sqlite3_vtab));
  return SQLITE_OK;
}
int xDisconnect(sqlite3_vtab *t) {
  free(t);
  return SQLITE_OK;
}
int xDestroy(sqlite3_vtab *t) {
  free(t);
  return SQLITE_OK;
}
int xOpen(sqlite3_vtab *na1, sqlite3_vtab_cursor **c) {
  *c = malloc(sizeof(sqlite3_vtab_cursor));
  return SQLITE_OK;
}
int xClose(sqlite3_vtab_cursor *c) {
  free(c);
  return SQLITE_OK;
}

int xBestIndex(sqlite3_vtab * vtab, sqlite3_index_info *info) {
  int seen_p1 = 0;
  int i;
  printf("## xBestIndex called:\n");
  printf("##   nConstraint=%d\n", info->nConstraint);
  for(i=0; i<info->nConstraint; i++){
    printf("##   constraint[%d]: col=%d op=%d usable=%d\n",
       i, info->aConstraint[i].iColumn, info->aConstraint[i].op,
       info->aConstraint[i].usable);
  }
  for (i = 0; i < info->nConstraint; ++i) {
    if (info->aConstraint[i].iColumn == P1_COLUMN) {
      if (!info->aConstraint[i].usable) {
        return SQLITE_CONSTRAINT;
      }
      seen_p1 = 1;
    }
  }
  if (!seen_p1) {
    vtab->zErrMsg = sqlite3_mprintf("p1 omitted");
    return SQLITE_ERROR;
  }
  return SQLITE_OK;
}
int xFilter(sqlite3_vtab_cursor *raw, int idxNum, const char *na1, int na2,
            sqlite3_value **na3) {
  return SQLITE_OK;
}
int xNext(sqlite3_vtab_cursor *raw) {
  return SQLITE_OK;
}
int xEof(sqlite3_vtab_cursor *raw) {
  return 1;
}
int xColumn(sqlite3_vtab_cursor *raw, sqlite3_context *ctx, int col) {
  return SQLITE_OK;
}

sqlite3_module module;

int sqlite3_testvtab_init(sqlite3 *db, char **pzErrMsg,
                          const sqlite3_api_routines *pApi) {
  SQLITE_EXTENSION_INIT2(pApi);
  module.xCreate = 0;
  module.xConnect = xConnect;
  module.xDisconnect = xDisconnect;
  module.xDestroy = xDestroy;
  module.xOpen = xOpen;
  module.xBestIndex = xBestIndex;
  module.xClose = xClose;
  module.xFilter = xFilter;
  module.xNext = xNext;
  module.xEof = xEof;
  module.xColumn = xColumn;
  return sqlite3_create_module_v2(db, "testvtab", &module, 0, 0);
}
